#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

typedef struct {
    int64_t key;   // prefix sum
    int val;       // first index where this sum appeared
    int used;      // 0 = empty, 1 = occupied
} Entry;

static int hash_idx(int64_t key, int size) {
    int64_t h = key ^ (key >> 32);
    int idx = (int)(h % size);
    if (idx < 0) idx += size;
    return idx;
}

static int find(Entry *table, int size, int64_t key) {
    int idx = hash_idx(key, size);
    while (table[idx].used) {
        if (table[idx].key == key) return idx;
        idx = (idx + 1) % size;
    }
    return -1; // not found
}

static int insert(Entry *table, int size, int64_t key, int val) {
    int idx = hash_idx(key, size);
    while (table[idx].used) {
        if (table[idx].key == key) return idx; // already present
        idx = (idx + 1) % size;
    }
    table[idx].used = 1;
    table[idx].key = key;
    table[idx].val = val;
    return idx;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int *arr = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        // hash table size: next power of two greater than 2*n for low load factor
        int size = 1;
        while (size < 2 * n) size <<= 1;
        Entry *table = (Entry *)calloc(size, sizeof(Entry));
        int64_t prefix = 0;
        int maxLen = 0;
        // store prefix sum 0 at index -1 to handle subarrays starting at 0
        insert(table, size, 0, -1);
        for (int i = 0; i < n; ++i) {
            prefix += arr[i];
            int pos = find(table, size, prefix);
            if (pos != -1) {
                int len = i - table[pos].val;
                if (len > maxLen) maxLen = len;
            } else {
                insert(table, size, prefix, i);
            }
        }
        printf("%d\n", maxLen);
        free(arr);
        free(table);
    }
    return 0;
}

