    while(T--) {
        int n; cin>>n;
        vector<int> a(n);
        for(int &x: a) cin>>x;
        unordered_map<long long,int> firstIdx;
        firstIdx.reserve(n*2);
        long long pref=0; int ans=0;
        firstIdx[0] = -1; // prefix sum 0 before array starts
        for(int i=0;i<n;++i){
            pref+=a[i];
            auto it = firstIdx.find(pref);
            if(it!=firstIdx.end()){
                ans = max(ans, i - it->second);
            }else{
                firstIdx[pref]=i;
            }
        }
        cout<<ans<<"\n";
    }
    return 0;
}

