import sys

def solve_one(arr):
    first = {0: -1}
    pref = 0
    ans = 0
    for i, v in enumerate(arr):
        pref += v
        if pref in first:
            ans = max(ans, i - first[pref])
        else:
            first[pref] = i
    return ans

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        out_lines.append(str(solve_one(arr)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

